INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('aboriginal-a5729396-moex-00284', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「湖和少年之間，其實是有血緣關係的。人工造湖的計畫把村人趕上高處，但童年的記憶還在湖底， 他總覺得自己和湖之間始終有一條臍帶相連，和魚一樣。」 根據上文，下列選項何者最符合文意？', '["作者如魚善泳，從小常在湖中嬉戲", "村人遷居高樓生活形態無奈被改變", "往日記憶並未隨著外境變遷而消失", "人工湖破壞了村人聚族而居的傳統"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00285', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「曾在戰爭中見過無法形容的流離失所，也失去了對人的信心，有一晚，腦子裡忽然浮現『人皆有不 忍人之心』那句話，才體認到人的高貴，讓人在徬徨中有肯定，也對自己有了肯定。沒有詩的感動， 就是麻木，就是生命的走向死亡。他說在歐洲留學時，他讀到很多現代詩人書寫死亡的詩，也就很快 地懂得他們的心意。那死亡不僅是個人，也是整個人間的遭遇。」 下列選項，最合乎本文意旨的是：', '["詩的感動來自不忍人之心，才能避免人性麻木", "戰爭摧毀人性的良善，藉由詩的記載引以為戒", "詩人將個人的遭遇與時代結合，表現時代精神", "苦難會刺激心靈，因此詩適合描寫痛苦的題材"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00286', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「曾經有很長的一段時間我與流行歌絕緣，以為清淨才是正道，愈來愈懼怕感覺生活。有一天卻偶然 被流行歌觸動，不全然是好不好聽的問題，而是那一刻，對外面的世界，我又有反應了。像經過了長 冬，冰雪融化，之後見山又是山。突然明白這就是人生況味，有時出世，有時入世。一首簡單明瞭的 歌曲，有時得來並不容易。情緒蓄積又蓄積，最後才跨越過了躁鬱徬徨與矯揉修辭，落地成歌。」 根據上文，下列選項正確的是：', '["多聽流行歌可以增加生活經驗", "內心成熟的人不喜歡聽流行歌", "被歌觸動也意味對生活有感覺", "越能呈現躁鬱徬徨的歌越深刻"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00287', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「我喜歡背影勝於正面。原因很簡單，靈魂是不需要五官的。五官很小，小到幾秒鐘就可以把故事說 完；背影很大，大到可以為它說一千零一個故事。臉是文，背影是詩；臉是現實，背影是夢。」 根據上文，下列選項何者正確？', '["背影才是靈魂所在，五官只是裝飾而無故事", "有靈魂才有故事，靈魂越多自然故事越豐富", "背影像詩給人想像空間大，故事就豐富精彩", "當現實壓力太大，躲到故事裡方能優游自在"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00288', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「對作家而言，他的書若能既受到攻擊，又得到讚譽的話，那是再好不過的事了。聲名就像羽毛球， 要是只在一邊打，馬上就會落地。要想讓它保持不墜，非得在兩頭打不可。」 根據上文，下列選項何者最符合文意？', '["文壇就像球場，必須要有公平的裁判", "中立的書評家對作品的行銷很有幫助", "對一部作品大加撻伐的書評家，肯定別有用心", "眾人異口同聲的讚譽作品，並非歷久不衰的保證"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00289', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「在餐廳吃豬腳配全麥麵包、德國啤酒，頗有地域、民族風味；然而必須有大肚量才能吃完一份德國 豬腳特餐，我所謂的肚量兼指對豬腳品質的寬容。」 根據上文，下列選項何者最接近作者對餐廳豬腳特餐的評價？', '["風味獨特難忘懷", "口味道地且美味", "份量大但味道差", "昂貴且品質不佳"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00290', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「通貨膨脹衝擊整個社會，校園營養午餐食材費、人事費跟著飛漲，但各縣市編列的營養午餐費用是 固定的。社會、家長都關心孩子營養午餐品質和安全，然而各縣市編列的預算不一，家長繳交的費用 不同，費用分配、使用也不全然公開，加上食材足跡不夠透明，讓家長對孩子的用餐無法放心、安心。」 根據上文，下列何者不在文中提出的議題脈絡或監督機制之列？', '["通貨膨脹引發家長對校園營養午餐品質的檢視", "縣市政府宜公開說明營養午餐預算編列與分配", "家長期待營養午餐統一窗口管理以維持公平性", "食材足跡透明化將有助於確保營養午餐的安全"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00291', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「過去的歷史教育總是不斷強調『同質性』，卻忽略了人類歷史之所以經常變動，正是因為存在著許 多異質性的因素。這些因素互相拉扯，但也互相形塑。如果我們不懂得多元地去看歷史上的各種異質 因素，歷史教育最後提供的，反而可能是先入為主的偏見和文化歧視。」 根據上文，下列選項最符合文意的是：', '["重視人類社會的異質性，有助於消除文化歧視", "唯有揚棄同質性，才能夠發揮歷史教育的功能", "人類之所以有各種異質性，皆源於偏見與歧視", "同質性的存在因素，並非其中一方同化另一方"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00292', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「在民主社會中，每一個公民都可以理直氣壯爭取自己的權益，同時也要懂得協調和妥協，不能將個 人權益無限上綱，無視社會整體得失。」 根據上文，下列選項何者最適當？', '["民主制度賦予人民的權益得來不易", "公民不宜濫用爭取權益的合法機制", "社會的集體利益一定要優先於個人權益", "公民需要協調與妥協才能完整保障權益"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL),
  ('aboriginal-a5729396-moex-00293', 'aboriginal-a5729396', 'aboriginal-a5729396-moex-112-34c7f7f6', 'sub-aboriginal-a5729396-02', NULL, 'single_choice', '「如果你最近升職，想改變造型、增加專業度，卻不知道怎麼做，你可能會上網搜尋『職場穿搭』。 倘若搜尋結果出現好幾筆『西裝外套』，你可能會繼續搜尋西裝外套品牌推薦。於是，你開始了購買 外套的顧客旅程。馬修‧史威茲認為，現今的行銷任務必須盡可能找出消費者每天提出的大量問題， 並在那些時刻幫他們找到解方，這種方式稱為『場景行銷』。」 根據上文，下列選項何者最不符合「場景行銷」關切的面向？', '["數據分析", "流行趨勢", "顧客導向", "職場需求"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:46+00:00", "source_pdf_sha1": "d8ccaed0f69f", "answer_pdf_sha1": "a19edca76f80", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "703", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "庭務員"}'::jsonb, NULL)
